// Middleware to validate and sanitize return_url
function validateReturnUrl(returnUrl) {
  if (!returnUrl) {
    return null;
  }

  // Only allow relative paths to prevent open redirect attacks
  try {
    // Block protocol-relative URLs
    if (returnUrl.startsWith('//')) {
      return null;
    }

    // Parse the URL - if it has a host/protocol, it's an absolute URL
    const parsed = new URL(returnUrl, 'http://localhost');

    // Only allow paths on the same origin (relative URLs)
    if (returnUrl.startsWith('/') && !returnUrl.startsWith('//')) {
      // Additional sanitization: remove any potentially dangerous characters
      const sanitized = parsed.pathname + parsed.search + parsed.hash;
      return sanitized;
    }

    // If it's an absolute URL, check against allowed domains
    const allowedDomains = [
      'localhost',
      'yourdomain.com',
      'www.yourdomain.com'
    ];

    if (allowedDomains.includes(parsed.hostname)) {
      return returnUrl;
    }

    return null;
  } catch (e) {
    return null;
  }
}

